# #### Network dropout
# Another startegy for regularization is dropout, which is randomly setting a fraction of the network units to 0 at each training iteration.
#
# Dropout can be interpreted in various ways, such as randomly sampling from an exponential number of different networks.

# %% [markdown] id="YnpoJMbbx-gY"
# ![Dropout-neural-network-model-a-is-a-standard-neural-network-b-is-the-same-network.png](data:image/png;base64,)


# %% colab={"base_uri": "https://localhost:8080/", "height": 405} executionInfo={"elapsed": 132684, "status": "ok", "timestamp": 1727901329782, "user": {"displayName": "Eva Dyer", "userId": "05212169819659068372"}, "user_tz": 240} id="H2BkZT7pyGmX" outputId="0f9a3eeb-4ff8-412a-b498-7f0a370359b9"
def get_model_with_dropout():
    model = nn.Sequential(
        nn.Conv2d(1, 8, 3),
        nn.ReLU(),
        nn.Conv2d(8, 8, 3),
        nn.ReLU(),
        nn.MaxPool2d(2),
        nn.Conv2d(8, 16, 3),
        nn.ReLU(),
        nn.MaxPool2d(2),
        nn.Flatten(),
        nn.Linear(400, 256),
        nn.ReLU(),
        nn.Dropout(0.2),
        nn.Linear(256, 1),
    )
    return model


